func SetClaims(ctx context.Context, claims *Claims) context.Context {
	return context.WithValue(ctx, contextKey{}, claims)
}

// GetClaims retrieves JWT claims from the context. Returns nil if not present.
func GetClaims(ctx context.Context) *Claims {
	claims, _ := ctx.Value(contextKey{}).(*Claims)
	return claims
}

// MustGetClaims retrieves JWT claims from the context.
// Panics if claims are not present — only call this in handlers behind auth middleware.
func MustGetClaims(ctx context.Context) *Claims {
	claims := GetClaims(ctx)
	if claims == nil {
		panic("auth: claims not found in context — handler must be behind auth middleware")
	}
	return claims
}

