// ─────────────────────────────────────────────────────────────────────────────
// ExportCSV — unit tests (no real DB)
// ─────────────────────────────────────────────────────────────────────────────

func TestExportCSV_InvalidFiltersJSON(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	h := handler.ExportCSV(nil, reg, 500)

	u := "/api/export/csv?filters=" + url.QueryEscape("not valid json")
	w := httptest.NewRecorder()
	r := httptest.NewRequest(http.MethodGet, u, nil)
	h(w, r)

	if w.Code != http.StatusBadRequest {
		t.Errorf("HTTP status: got %d, want %d", w.Code, http.StatusBadRequest)
	}

	var body map[string]string
	if err := json.NewDecoder(w.Body).Decode(&body); err != nil {
		t.Fatalf("decode body: %v", err)
	}
	if body["error"] == "" {
		t.Error("expected non-empty error message")
	}
}

func TestExportCSV_InvalidFilterField(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	h := handler.ExportCSV(nil, reg, 500)

	filters := `[{"field":"does_not_exist","value":{"value":"x"}}]`
	u := "/api/export/csv?filters=" + url.QueryEscape(filters)
	w := httptest.NewRecorder()
	r := httptest.NewRequest(http.MethodGet, u, nil)
	h(w, r)

	if w.Code != http.StatusBadRequest {
		t.Errorf("HTTP status: got %d, want %d", w.Code, http.StatusBadRequest)
	}

	var body struct {
		Errors []struct {
			Field   string `json:"field"`
			Message string `json:"message"`
		} `json:"errors"`
	}
	if err := json.NewDecoder(w.Body).Decode(&body); err != nil {
		t.Fatalf("decode body: %v", err)
	}
	if len(body.Errors) == 0 {
		t.Error("expected at least 1 validation error")
	}
}

func TestExportCSV_InvalidUserLatLng(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	h := handler.ExportCSV(nil, reg, 500)

	u := "/api/export/csv?userLat=abc&userLng=def"
	w := httptest.NewRecorder()
	r := httptest.NewRequest(http.MethodGet, u, nil)
	h(w, r)

	if w.Code != http.StatusBadRequest {
		t.Errorf("HTTP status: got %d, want %d", w.Code, http.StatusBadRequest)
	}
}

func TestExportCSV_SortDistanceWithoutLocation(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	h := handler.ExportCSV(nil, reg, 500)

	u := "/api/export/csv?sort=DISTANCE"
	w := httptest.NewRecorder()
	r := httptest.NewRequest(http.MethodGet, u, nil)
	h(w, r)

	// ValidateRequest should catch sort=DISTANCE without userLocation.
	if w.Code != http.StatusBadRequest {
		t.Errorf("HTTP status: got %d, want %d", w.Code, http.StatusBadRequest)
	}
}

