// restrictedTestRegistry returns a registry with a single restricted enum field.
func restrictedTestRegistry() *search.Registry {
	f := search.NewTestSingleEnumField("secret_field", search.SearchabilityRestricted, []search.EnumOption{
		{Value: "a", Label: "A"},
		{Value: "b", Label: "B"},
	})
	return search.NewRegistryFromFields([]search.Field{f})
}

func TestExportCSV_RestrictedField_Anonymous(t *testing.T) {
	t.Parallel()
	reg := restrictedTestRegistry()
	h := handler.ExportCSV(nil, reg, 500)

	filters := `[{"field":"secret_field","value":{"value":"a"}}]`
	u := "/api/export/csv?filters=" + url.QueryEscape(filters)
	w := httptest.NewRecorder()
	r := httptest.NewRequest(http.MethodGet, u, nil)
	// No auth claims in context — anonymous request.
	h(w, r)

	if w.Code != http.StatusBadRequest {
		t.Fatalf("HTTP status: got %d, want %d", w.Code, http.StatusBadRequest)
	}

	var body struct {
		Errors []struct {
			Field   string `json:"field"`
			Message string `json:"message"`
		} `json:"errors"`
	}
	if err := json.NewDecoder(w.Body).Decode(&body); err != nil {
		t.Fatalf("decode body: %v", err)
	}
	if len(body.Errors) == 0 {
		t.Fatal("expected validation errors for restricted field")
	}
	found := false
	for _, e := range body.Errors {
		if e.Field == "secret_field" && strings.Contains(e.Message, "authentication") {
			found = true
			break
		}
	}
	if !found {
		t.Errorf("expected auth-required error for secret_field, got: %+v", body.Errors)
	}
}

func TestExportCSV_RestrictedField_Authenticated(t *testing.T) {
	t.Parallel()
	reg := restrictedTestRegistry()
	h := handler.ExportCSV(nil, reg, 500)

	filters := `[{"field":"secret_field","value":{"value":"a"}}]`
	u := "/api/export/csv?filters=" + url.QueryEscape(filters)
	w := httptest.NewRecorder()
	r := httptest.NewRequest(http.MethodGet, u, nil)

	// Inject auth claims into context — authenticated request.
	ctx := auth.SetClaims(r.Context(), &auth.Claims{})
	r = r.WithContext(ctx)

	// The handler will pass validation but panic on nil DB pool when
	// building the export query. That's expected — we only care that
	// the restricted field is accepted for authenticated callers.
	defer func() {
		if rec := recover(); rec != nil {
			// Expected: nil pool dereference after validation passes.
		}
	}()
	h(w, r)

	// If we reach here without panic, validation returned a 400 which is wrong.
	if w.Code == http.StatusBadRequest {
		t.Fatalf("authenticated request should not be rejected; got 400 with body: %s", w.Body.String())
	}
}

